setd("6.2", String.raw`<svg viewBox="0 0 600 250" width="100%" style="max-width:600px" xmlns="http://www.w3.org/2000/svg" font-family="system-ui,Segoe UI,Arial" font-size="11.5"><text x="300.0" y="22.0" text-anchor="middle" fill="#1f2a44" font-size="13.0" font-weight="700">The chain rule multiplies the slopes along the path</text><text x="66.0" y="119.0" text-anchor="middle" fill="#1f2a44" font-size="15" font-weight="700">x</text><line x1="80.0" y1="115.0" x2="143.7" y2="115.0" stroke="#9aa6bd" stroke-width="2" stroke-linecap="round"/><polygon points="150.0,115.0 143.6,117.9 143.6,112.1" fill="#9aa6bd" stroke="none" stroke-width="1.0"/><text x="115.0" y="105.0" text-anchor="middle" fill="#2a6f97" font-size="10">g′(x)=2</text><rect x="154.0" y="87.0" width="84.0" height="56.0" rx="10" fill="#dbe8fb" stroke="#2a6f97" stroke-width="1.6"/><text x="196.0" y="120.0" text-anchor="middle" fill="#2a6f97" font-size="12.5" font-weight="700">u = g(x)</text><line x1="240.0" y1="115.0" x2="303.7" y2="115.0" stroke="#9aa6bd" stroke-width="2" stroke-linecap="round"/><polygon points="310.0,115.0 303.6,117.9 303.6,112.1" fill="#9aa6bd" stroke="none" stroke-width="1.0"/><text x="275.0" y="105.0" text-anchor="middle" fill="#3a7d44" font-size="10">f′(u)=3</text><rect x="314.0" y="87.0" width="84.0" height="56.0" rx="10" fill="#e3efe5" stroke="#3a7d44" stroke-width="1.6"/><text x="356.0" y="120.0" text-anchor="middle" fill="#3a7d44" font-size="12.5" font-weight="700">y = f(u)</text><line x1="400.0" y1="115.0" x2="463.7" y2="115.0" stroke="#9aa6bd" stroke-width="2" stroke-linecap="round"/><polygon points="470.0,115.0 463.6,117.9 463.6,112.1" fill="#9aa6bd" stroke="none" stroke-width="1.0"/><text x="506.0" y="119.0" text-anchor="middle" fill="#1f2a44" font-size="15" font-weight="700">y</text><text x="300.0" y="192.0" text-anchor="middle" fill="#4f46e5" font-size="15" font-weight="700">dy/dx = f′(u) · g′(x) = 3 · 2 = 6</text><text x="300.0" y="242.0" text-anchor="middle" fill="#6b7891" font-size="10.5" font-style="italic">Backprop is exactly this: multiply the local slopes from the output back to the input.</text></svg>`);
