setd("9.1", String.raw`<svg viewBox="0 0 560 285" width="100%" style="max-width:560px" xmlns="http://www.w3.org/2000/svg" font-family="system-ui,Segoe UI,Arial" font-size="11.5"><text x="280.0" y="22.0" text-anchor="middle" fill="#1f2a44" font-size="13.0" font-weight="700">Sample space Ω holds every outcome; events are regions inside it</text><rect x="115.0" y="58.0" width="330.0" height="180.0" rx="6" fill="#eef2f7" stroke="#6b7891" stroke-width="1.4"/><text x="432.0" y="76.0" text-anchor="end" fill="#4a5878" font-size="15" font-weight="700">Ω</text><circle cx="238" cy="150" r="64" fill="#2a6f97" fill-opacity="0.28" stroke="#2a6f97" stroke-width="1.8"/><circle cx="330" cy="150" r="64" fill="#3a7d44" fill-opacity="0.28" stroke="#3a7d44" stroke-width="1.8"/><text x="208.0" y="150.0" text-anchor="middle" fill="#2a6f97" font-size="14" font-weight="700">A</text><text x="360.0" y="150.0" text-anchor="middle" fill="#3a7d44" font-size="14" font-weight="700">B</text><text x="284.0" y="150.0" text-anchor="middle" fill="#1f2a44" font-size="10.5" font-weight="600">A∩B</text><text x="280.0" y="277.0" text-anchor="middle" fill="#6b7891" font-size="10.5" font-style="italic">Probability is area: P(event) = its share of Ω. Overlap A∩B is the outcomes in both events.</text></svg>`);
setd("9.2", String.raw`<svg viewBox="0 0 560 290" width="100%" style="max-width:560px" xmlns="http://www.w3.org/2000/svg" font-family="system-ui,Segoe UI,Arial" font-size="11.5"><text x="280.0" y="22.0" text-anchor="middle" fill="#1f2a44" font-size="13.0" font-weight="700">Conditioning on B shrinks the world to B</text><rect x="115.0" y="58.0" width="330.0" height="150.0" rx="6" fill="#fff" stroke="#6b7891" stroke-width="1.2"/><rect x="115.0" y="58.0" width="330.0" height="150.0" rx="6" fill="#eef2f7" stroke="#6b7891" stroke-width="1.3" opacity="0.5"/><circle cx="238" cy="132" r="60" fill="#6b7891" fill-opacity="0.16" stroke="#6b7891" stroke-width="1.8"/><circle cx="330" cy="132" r="60" fill="#3a7d44" fill-opacity="0.34" stroke="#3a7d44" stroke-width="1.8"/><text x="206.0" y="132.0" text-anchor="middle" fill="#6b7891" font-size="13" font-weight="700">A</text><text x="360.0" y="120.0" text-anchor="middle" fill="#3a7d44" font-size="13" font-weight="700">B</text><text x="285.0" y="132.0" text-anchor="middle" fill="#1f2a44" font-size="10" font-weight="700">A∩B</text><text x="280.0" y="244.0" text-anchor="middle" fill="#1f2a44" font-size="13" font-weight="700">P(A | B) = area(A∩B) / area(B)</text><text x="280.0" y="282.0" text-anchor="middle" fill="#6b7891" font-size="10.5" font-style="italic">Given B happened, only B's area counts — the chance of A is its slice of B, not of all Ω.</text></svg>`);
setd("9.3", String.raw`<svg viewBox="0 0 560 300" width="100%" style="max-width:560px" xmlns="http://www.w3.org/2000/svg" font-family="system-ui,Segoe UI,Arial" font-size="11.5"><text x="280.0" y="22.0" text-anchor="middle" fill="#1f2a44" font-size="13.0" font-weight="700">Bayes: a positive test is mostly false alarms when disease is rare</text><rect x="80.0" y="60.0" width="24.0" height="169.2" rx="0" fill="#c0392b" stroke="none" stroke-width="1.0"/><rect x="80.0" y="229.2" width="24.0" height="18.8" rx="0" fill="#f7e0dc" stroke="none" stroke-width="1.0"/><rect x="104.0" y="60.0" width="276.0" height="28.2" rx="0" fill="#b9722a" stroke="none" stroke-width="1.0"/><rect x="104.0" y="88.2" width="276.0" height="159.8" rx="0" fill="#eef2f7" stroke="none" stroke-width="1.0"/><rect x="80.0" y="60.0" width="300.0" height="188.0" rx="0" fill="none" stroke="#6b7891" stroke-width="1.3"/><line x1="104.0" y1="60.0" x2="104.0" y2="248.0" stroke="#6b7891" stroke-width="1" stroke-linecap="round"/><text x="92.0" y="262.0" text-anchor="middle" fill="#c0392b" font-size="9.5" font-weight="600">sick 8%</text><text x="242.0" y="262.0" text-anchor="middle" fill="#6b7891" font-size="9.5">healthy 92%</text><text x="400.0" y="110.0" text-anchor="start" fill="#c0392b" font-size="10.5" font-weight="600">true positives</text><text x="400.0" y="125.0" text-anchor="start" fill="#4a5878" font-size="9.5">= 8%×90% = .072</text><text x="400.0" y="150.0" text-anchor="start" fill="#b9722a" font-size="10.5" font-weight="600">false positives</text><text x="400.0" y="165.0" text-anchor="start" fill="#4a5878" font-size="9.5">= 92%×15% = .138</text><text x="400.0" y="195.0" text-anchor="start" fill="#1f2a44" font-size="11" font-weight="700">P(sick | +)</text><text x="400.0" y="211.0" text-anchor="start" fill="#4f46e5" font-size="12" font-weight="700">≈ 34%</text><text x="280.0" y="292.0" text-anchor="middle" fill="#6b7891" font-size="10.5" font-style="italic">The wide amber band (false alarms) dwarfs the thin red sliver (true cases) — so “positive” ≠ “sick”.</text></svg>`);
