setd("12.2", String.raw`<svg viewBox="0 0 560 300" width="100%" style="max-width:560px" xmlns="http://www.w3.org/2000/svg" font-family="system-ui,Segoe UI,Arial" font-size="11.5"><text x="280.0" y="22.0" text-anchor="middle" fill="#1f2a44" font-size="13.0" font-weight="700">Cross-entropy: the bits you pay coding true p with model q</text><rect x="75.9" y="88.8" width="23.0" height="153.2" rx="0" fill="#dbe8fb" stroke="#2a6f97" stroke-width="1.1"/><rect x="102.9" y="165.4" width="23.0" height="76.6" rx="0" fill="#f7e7d2" stroke="#b9722a" stroke-width="1.1"/><text x="100.9" y="257.0" text-anchor="middle" fill="#6b7891" font-size="8.5">class 0</text><rect x="161.6" y="150.1" width="23.0" height="91.9" rx="0" fill="#dbe8fb" stroke="#2a6f97" stroke-width="1.1"/><rect x="188.6" y="165.4" width="23.0" height="76.6" rx="0" fill="#f7e7d2" stroke="#b9722a" stroke-width="1.1"/><text x="186.6" y="257.0" text-anchor="middle" fill="#6b7891" font-size="8.5">class 1</text><rect x="247.3" y="196.0" width="23.0" height="46.0" rx="0" fill="#dbe8fb" stroke="#2a6f97" stroke-width="1.1"/><rect x="274.3" y="165.4" width="23.0" height="76.6" rx="0" fill="#f7e7d2" stroke="#b9722a" stroke-width="1.1"/><text x="272.3" y="257.0" text-anchor="middle" fill="#6b7891" font-size="8.5">class 2</text><rect x="333.0" y="226.7" width="23.0" height="15.3" rx="0" fill="#dbe8fb" stroke="#2a6f97" stroke-width="1.1"/><rect x="360.0" y="165.4" width="23.0" height="76.6" rx="0" fill="#f7e7d2" stroke="#b9722a" stroke-width="1.1"/><text x="358.0" y="257.0" text-anchor="middle" fill="#6b7891" font-size="8.5">class 3</text><line x1="58.0" y1="242.0" x2="418.0" y2="242.0" stroke="#9aa6bd" stroke-width="1.3" stroke-linecap="round"/><line x1="58.0" y1="52.0" x2="58.0" y2="242.0" stroke="#9aa6bd" stroke-width="1.3" stroke-linecap="round"/><rect x="438.0" y="60.0" width="12.0" height="12.0" rx="0" fill="#dbe8fb" stroke="#2a6f97" stroke-width="1.0"/><text x="456.0" y="70.0" text-anchor="start" fill="#4a5878" font-size="10">true p</text><rect x="438.0" y="80.0" width="12.0" height="12.0" rx="0" fill="#f7e7d2" stroke="#b9722a" stroke-width="1.0"/><text x="456.0" y="90.0" text-anchor="start" fill="#4a5878" font-size="10">model q</text><text x="438.0" y="124.0" text-anchor="start" fill="#1f2a44" font-size="11" font-weight="700">KL(p‖q)</text><text x="438.0" y="141.0" text-anchor="start" fill="#4f46e5" font-size="11" font-weight="700">= 0.35 bits</text><text x="438.0" y="164.0" text-anchor="start" fill="#6b7891" font-size="9.5">extra cost of</text><text x="438.0" y="178.0" text-anchor="start" fill="#6b7891" font-size="9.5">the mismatch</text><text x="280.0" y="292.0" text-anchor="middle" fill="#6b7891" font-size="9.9" font-style="italic">H(p,q) = H(p) + KL(p‖q): the gap between true p (blue) and model q (amber) is the KL penalty you minimize.</text></svg>`);
setd("12.3", String.raw`<svg viewBox="0 0 560 290" width="100%" style="max-width:560px" xmlns="http://www.w3.org/2000/svg" font-family="system-ui,Segoe UI,Arial" font-size="11.5"><text x="280.0" y="22.0" text-anchor="middle" fill="#1f2a44" font-size="13.0" font-weight="700">Mutual information is the overlap of two entropies</text><circle cx="238" cy="158" r="74" fill="#2a6f97" fill-opacity="0.26" stroke="#2a6f97" stroke-width="1.8"/><circle cx="340" cy="158" r="74" fill="#3a7d44" fill-opacity="0.26" stroke="#3a7d44" stroke-width="1.8"/><text x="196.0" y="160.0" text-anchor="middle" fill="#2a6f97" font-size="10" font-weight="600">H(X|Y)</text><text x="382.0" y="160.0" text-anchor="middle" fill="#3a7d44" font-size="10" font-weight="600">H(Y|X)</text><text x="289.0" y="160.0" text-anchor="middle" fill="#1f2a44" font-size="10.5" font-weight="700">I(X;Y)</text><text x="200.0" y="66.0" text-anchor="middle" fill="#2a6f97" font-size="12" font-weight="700">H(X)</text><text x="378.0" y="66.0" text-anchor="middle" fill="#3a7d44" font-size="12" font-weight="700">H(Y)</text><line x1="170.0" y1="80.0" x2="238.0" y2="120.0" stroke="#2a6f97" stroke-width="0.8" stroke-dasharray="3 3" stroke-linecap="round"/><line x1="408.0" y1="80.0" x2="340.0" y2="120.0" stroke="#3a7d44" stroke-width="0.8" stroke-dasharray="3 3" stroke-linecap="round"/><text x="280.0" y="282.0" text-anchor="middle" fill="#6b7891" font-size="10.4" font-style="italic">I(X;Y) is the shared middle — how much knowing one variable shrinks your uncertainty about the other.</text></svg>`);
