setd("13.2", String.raw`<svg viewBox="0 0 560 290" width="100%" style="max-width:560px" xmlns="http://www.w3.org/2000/svg" font-family="system-ui,Segoe UI,Arial" font-size="11.5"><text x="280.0" y="22.0" text-anchor="middle" fill="#1f2a44" font-size="13.0" font-weight="700">Log-sum-exp: subtract the max so exp never overflows</text><text x="66.0" y="74.0" text-anchor="start" fill="#4a5878" font-size="10.5" font-weight="600">raw logits</text><rect x="66.0" y="86.0" width="60.0" height="26.0" rx="5" fill="#dbe8fb" stroke="#2a6f97" stroke-width="1.2"/><text x="96.0" y="103.0" text-anchor="middle" fill="#2a6f97" font-size="10.5" font-weight="600">88</text><rect x="136.0" y="86.0" width="60.0" height="26.0" rx="5" fill="#dbe8fb" stroke="#2a6f97" stroke-width="1.2"/><text x="166.0" y="103.0" text-anchor="middle" fill="#2a6f97" font-size="10.5" font-weight="600">89</text><rect x="206.0" y="86.0" width="60.0" height="26.0" rx="5" fill="#dbe8fb" stroke="#2a6f97" stroke-width="1.2"/><text x="236.0" y="103.0" text-anchor="middle" fill="#2a6f97" font-size="10.5" font-weight="600">90</text><text x="292.0" y="105.0" text-anchor="start" fill="#6b7891" font-size="11">exp →</text><rect x="352.0" y="86.0" width="74.0" height="26.0" rx="5" fill="#f7e0dc" stroke="#c0392b" stroke-width="1.2"/><text x="389.0" y="103.0" text-anchor="middle" fill="#c0392b" font-size="10.5" font-weight="600">1.6e38</text><rect x="440.0" y="86.0" width="94.0" height="26.0" rx="5" fill="#f7e0dc" stroke="#c0392b" stroke-width="1.2"/><text x="487.0" y="103.0" text-anchor="middle" fill="#c0392b" font-size="10.5" font-weight="600">∞ overflow ✗</text><text x="66.0" y="152.0" text-anchor="start" fill="#4a5878" font-size="10.5" font-weight="600">minus max (90)</text><rect x="66.0" y="164.0" width="60.0" height="26.0" rx="5" fill="#e3efe5" stroke="#3a7d44" stroke-width="1.2"/><text x="96.0" y="181.0" text-anchor="middle" fill="#3a7d44" font-size="10.5" font-weight="600">−2</text><rect x="136.0" y="164.0" width="60.0" height="26.0" rx="5" fill="#e3efe5" stroke="#3a7d44" stroke-width="1.2"/><text x="166.0" y="181.0" text-anchor="middle" fill="#3a7d44" font-size="10.5" font-weight="600">−1</text><rect x="206.0" y="164.0" width="60.0" height="26.0" rx="5" fill="#e3efe5" stroke="#3a7d44" stroke-width="1.2"/><text x="236.0" y="181.0" text-anchor="middle" fill="#3a7d44" font-size="10.5" font-weight="600">0</text><text x="292.0" y="183.0" text-anchor="start" fill="#6b7891" font-size="11">exp →</text><rect x="352.0" y="164.0" width="74.0" height="26.0" rx="5" fill="#e3efe5" stroke="#3a7d44" stroke-width="1.2"/><text x="389.0" y="181.0" text-anchor="middle" fill="#3a7d44" font-size="10.5" font-weight="600">0.14</text><rect x="440.0" y="164.0" width="94.0" height="26.0" rx="5" fill="#e3efe5" stroke="#3a7d44" stroke-width="1.2"/><text x="487.0" y="181.0" text-anchor="middle" fill="#3a7d44" font-size="10.5" font-weight="600">1.0  ✓ safe</text><text x="280.0" y="282.0" text-anchor="middle" fill="#6b7891" font-size="9.5" font-style="italic">Softmax is unchanged if you shift every logit by a constant — so subtract the max and each exp lands in (0, 1].</text></svg>`);
setd("13.3", String.raw`<svg viewBox="0 0 560 262" width="100%" style="max-width:560px" xmlns="http://www.w3.org/2000/svg" font-family="system-ui,Segoe UI,Arial" font-size="11.5"><text x="280.0" y="22.0" text-anchor="middle" fill="#1f2a44" font-size="13.0" font-weight="700">Factorizations rewrite A as a product of simpler triangles</text><rect x="78.0" y="64.0" width="92.0" height="92.0" rx="0" fill="#fff" stroke="#6b7891" stroke-width="1.3"/><rect x="80.0" y="66.0" width="88.0" height="88.0" rx="0" fill="#e5e7ff" stroke="none" stroke-width="1.0"/><rect x="78.0" y="64.0" width="92.0" height="92.0" rx="0" fill="none" stroke="#6b7891" stroke-width="1.3"/><text x="124.0" y="178.0" text-anchor="middle" fill="#4a5878" font-size="10.5" font-weight="600">A (any square)</text><text x="190.0" y="112.0" text-anchor="middle" fill="#1f2a44" font-size="22" font-weight="700">=</text><rect x="220.0" y="64.0" width="92.0" height="92.0" rx="0" fill="#fff" stroke="#6b7891" stroke-width="1.3"/><polygon points="220.0,64.0 220.0,156.0 312.0,156.0" fill="#dbe8fb" stroke="none" stroke-width="1.0"/><rect x="220.0" y="64.0" width="92.0" height="92.0" rx="0" fill="none" stroke="#6b7891" stroke-width="1.3"/><text x="266.0" y="178.0" text-anchor="middle" fill="#4a5878" font-size="10.5" font-weight="600">L (lower △)</text><text x="332.0" y="112.0" text-anchor="middle" fill="#1f2a44" font-size="22" font-weight="700">·</text><rect x="360.0" y="64.0" width="92.0" height="92.0" rx="0" fill="#fff" stroke="#6b7891" stroke-width="1.3"/><polygon points="360.0,64.0 452.0,64.0 452.0,156.0" fill="#e3efe5" stroke="none" stroke-width="1.0"/><rect x="360.0" y="64.0" width="92.0" height="92.0" rx="0" fill="none" stroke="#6b7891" stroke-width="1.3"/><text x="406.0" y="178.0" text-anchor="middle" fill="#4a5878" font-size="10.5" font-weight="600">U (upper △)</text><text x="280.0" y="254.0" text-anchor="middle" fill="#6b7891" font-size="8.8" font-style="italic">LU = lower × upper triangular, so Ax=b solves by easy substitution. For symmetric-PD A, Cholesky A=LLᵀ halves the work.</text></svg>`);
